const fs = require('fs');
const path = require('path');

// UPDATE THIS PATH to match your n8n server's docmail directory
const dir = '/home/node/docmail';

if (!fs.existsSync(dir)) {
  return [{ json: { files: [], count: 0 } }];
}

const fileNames = fs.readdirSync(dir)
  .filter(f => f.startsWith('docmail_') && f.endsWith('.html'));

if (fileNames.length === 0) {
  return [{ json: { files: [], count: 0 } }];
}

const item = {
  json: {
    count: fileNames.length,
    allFiles: fileNames.join(', '),
    fileNames: fileNames,
    attachmentKeys: fileNames.map((_, i) => 'file_' + i).join(',')
  },
  binary: {}
};

for (let i = 0; i < fileNames.length; i++) {
  const filePath = path.join(dir, fileNames[i]);
  const content = fs.readFileSync(filePath);
  item.binary['file_' + i] = {
    data: content.toString('base64'),
    mimeType: 'text/html',
    fileName: fileNames[i]
  };
}

return [item];

const fs = require('fs');
const path = require('path');

// UPDATE THIS PATH to match your n8n server's docmail directory
const dir = '/home/node/docmail';
const archiveDir = '/home/node/docmail/archive';

if (!fs.existsSync(archiveDir)) {
  fs.mkdirSync(archiveDir, { recursive: true });
}

const fileNames = $('List Files').first().json.fileNames || [];
const archived = [];
for (const fileName of fileNames) {
  const src = path.join(dir, fileName);
  const dst = path.join(archiveDir, fileName);
  if (fs.existsSync(src)) {
    fs.renameSync(src, dst);
    archived.push(fileName);
  }
}

return [{ json: { archived, count: archived.length } }];
